import React from "react";
import Controller from "./components/controller";
import GetProps from "./components/getProps";
class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      edit: true,
      preview: false,
      infos: GetProps.getDummy(),
    };
    this.onChange = this.onChange.bind(this);
    this.functions = {
      stringUpdate: (value, string) => {
        this.setState({
          infos: GetProps.updateString(value, string, this.state.infos),
        });
      },
      updateExp: (id, value, classHandle) => {
        this.setState({
          infos: GetProps.updateExp(id, value, classHandle, this.state.infos),
        });
      },
      updateDiploma: (id, value, classHandle) => {
        this.setState({
          infos: GetProps.updateDiploma(
            id,
            value,
            classHandle,
            this.state.infos
          ),
        });
      },
      updateLang: (id, text, value) => {
        this.setState({
          infos: GetProps.updateLang(id, text, value, this.state.infos),
        });
      },
      updateLevel: (id, value) => {
        this.setState({
          infos: GetProps.updateLevel(id, value, this.state.infos),
        });
      },
      updateSkill: (id, value) => {
        this.setState({
          infos: GetProps.updateSkill(id, value, this.state.infos),
        });
      },
      updateDuration: (id, value) => {
        this.setState({
          infos : GetProps.updateDuration(id, value, this.state.infos)
        })
      },
      addExp: () => {
        this.setState({
          infos: GetProps.addExp(this.state.infos),
        });
      },
      addDiploma: () => {
        this.setState({
          infos: GetProps.addDiploma(this.state.infos),
        });
      },
      addDesc: (id) => {
        this.setState({
          infos: GetProps.addDesc(id, this.state.infos),
        });
      },
      addLang: () => {
        this.setState({
          infos: GetProps.addLang(this.state.infos),
        });
      },
      addSkill: () => {
        this.setState({
          infos: GetProps.addSkill(this.state.infos),
        });
      },
      removeElement: (id, string) => {
        this.setState({
          infos: GetProps.removeElement(id, string, this.state.infos),
        });
      },
    };
  }
  onChange = (e) => {
    if (e.target.className === "edit")
      this.setState({ edit: true, preview: false });
    if (e.target.className === "prev")
      this.setState({ edit: false, preview: true });
  };
  render() {
    const switchPrevEdit = {
      edit: this.state.edit,
      preview: this.state.preview,
    };
    return (
      <>
        <div className="switch">
          <button
            className="edit"
            id="switcher"
            value={this.state.edit}
            onClick={this.onChange}
          >
            Edit Mode
          </button>
          <button
            className="prev"
            id="switcher"
            value={this.state.preview}
            onClick={this.onChange}
          >
            Preview Mode
          </button>
        </div>
        <Controller
          switcher={switchPrevEdit}
          data={this.state.infos}
          onDataChange={this.functions}
        />
      </>
    );
  }
}
export default App;
