import React from "react";
class Address extends React.Component {
  constructor(props) {
    super(props);
    this.handleChange = this.handleChange.bind(this);
  }
  handleChange = (e) => {
    if (e.target.id === "street")
      this.props.onDataChange.stringUpdate(e.target.value, "street");
    if (e.target.id === "zip")
      this.props.onDataChange.stringUpdate(e.target.value, "zip");
    if (e.target.id === "city")
      this.props.onDataChange.stringUpdate(e.target.value, "city");
  };
  render() {
    return (
      <div className="sub-container">
        <div data-style="label-input">
          <label>Street Address</label>
          <input
            type="text"
            value={this.props.address.street}
            onChange={this.handleChange}
            id="street"
          ></input>
        </div>
        <div data-style="label-input">
          <label>Zip Code</label>
          <input
            type="text"
            value={this.props.address.zip}
            onChange={this.handleChange}
            id="zip"
            pattern="[0-9]{5}"
          ></input>
        </div>
        <div data-style="label-input">
          <label>City</label>
          <input
            type="text"
            value={this.props.address.city}
            onChange={this.handleChange}
            id="city"
          ></input>
        </div>
      </div>
    );
  }
}
export default Address;
