import React from "react";
class Experiences extends React.Component {
    render(){
        const experiencesList = this.props.experiences.map(el => 
            <div className="experience">
                <h4>{el[0].title.text}</h4>
                <div className="small">
                    <h5>{el[0].employer.text}</h5>
                    <p>{el[0].location.text}</p>
                    <p>{el[0].duration[0].text}</p>
                    <p>{el[0].duration[1].text}</p>
                </div>
                <div className="descriptions">
                    <Description data={el[0].description}/>
                </div>
            </div>
            )
        return(
            <>
                {experiencesList}
            </>
        )
    }
}
class Description extends React.Component{
    render(){
        const descriptionsList = this.props.data.map(el=>
            <div>
                <p>{el[0].text}</p>
            </div>
            )
        return(
            <>
                {descriptionsList}
            </>
        )
    }
}
export default Experiences;