import React from "react";
import List from "./LanguagesList";
import removeIcon from "../../svg/delete-svgrepo-com.svg";
class Languages extends React.Component {
  constructor() {
    super();
        this.removeElement = this.removeElement.bind(this);
    this.updateLevel = this.updateLevel.bind(this);
  }
  updateLevel(e) {
    this.props.onDataChange.updateLevel(e.target.id, e.target.value);
  }
  removeElement(e) {
    this.props.onDataChange.removeElement(e.target.id, "language");
  }
  render() {
    const list = this.props.languages.map((el) => (
      <div data-style="input-close" className="language">
        <List data={el} onDataChange={this.props.onDataChange} />
        <select
          className="level"
          id={el[0].id}
          value={el[0].level}
          onChange={this.updateLevel}
        >
          <option value="default">Select a level</option>
          <option value="beginner">Beginner</option>
          <option value="intermediate">Intermediate</option>
          <option value="advanced">Advanced</option>
        </select>
        <img
          src={removeIcon}
          alt="close"
          onClick={this.removeElement}
          id={el[0].id}
        ></img>
      </div>
    ));
    return (
      <>
        {list}
      </>
    );
  }
}
export default Languages;
