import React from "react";
import Edit from "./edit/Main";
import Preview from "./preview/Main";
class Controller extends React.Component {
    render() {
        if (this.props.switcher.edit === true) {
            return (
                <Edit data={this.props.data} onDataChange={this.props.onDataChange}/>
            )
        } else {
            return (
                <Preview data={this.props.data} />
            )
        }
    }
}
export default Controller;