const GetProps = {
  getDummy() {
    return {
      details,
      address,
      experiences,
      diplomas,
      skills,
      languages,
      about,
      title,
    };
  },
  updateString(value, string, state) {
    // Personal details
    if (string === "first") state.details.firstName = value;
    if (string === "last") state.details.lastName = value;
    if (string === "phone") state.details.phone = value;
    if (string === "email") state.details.email = value;
    // address
    if (string === "city") state.address.city = value;
    if (string === "zip") state.address.zip = value;
    if (string === "street") state.address.street = value;
    // About
    if (string === "about") state.about = value;
    if (string === "title") state.title = value;
    return state;
  },
  updateExp(id, value, classHandle, state) {
    if (classHandle === "title") {
      for (let experience of state.experiences) {
        if (experience[0].title.id === id) experience[0].title.text = value;
      }
    }
    if (classHandle === "description") {
      for (let i = 0; i < state.experiences.length; i++) {
        let desc = state.experiences[i][0].description;
        for (let j = 0; j < desc.length; j++) {
          if (desc[j][0].id === id) desc[j][0].text = value;
        }
      }
    }
    if (classHandle === "employer") {
      const el = state.experiences.filter((el) => el[0].employer.id === id);
      el[0][0].employer.text = value;
    }
    if (classHandle === "location") {
      const el = state.experiences.filter((el) => el[0].location.id === id);
      el[0][0].location.text = value;
    }
    return state;
  },
  updateDiploma(id, value, classHandle, state) {
    const diploma = state.diplomas.filter((el) => el[0].id === id);
    if (classHandle === "location") diploma[0][0].location = value;
    if (classHandle === "date") diploma[0][0].date = value;
    if (classHandle === "title") diploma[0][0].title = value;
    if (classHandle === "org") diploma[0][0].org = value;
    return state;
  },
  updateLang(id, text, value, state) {
    const lang = state.languages.filter((el) => el[0].id === id);
    lang[0][0].code = value;
    lang[0][0].lang = text;
    return state;
  },
  updateLevel(id, value, state) {
    const lang = state.languages.filter((el) => el[0].id === id);
    lang[0][0].level = value;
    return state;
  },
  updateSkill(id, value, state) {
    const skill = state.skills.filter((el) => el[0].id === id);
    skill[0][0].text = value;
    return state;
  },
  updateDuration(id, value, state){
    for (let exp of experiences) {
      let from = exp[0].duration[0];
      let to = exp[0].duration[1];
      if (from[0].id===id) from[0].text = value;
      if(to[0].id===id) to[0].text = value;
    }
    return state;
  },
  addExp(state) {
    state.experiences.push([
      {
        title: { text: "", id: uniqid() },
        description: [[{ text: "", id: uniqid() }]],
        employer: { text: "", id: uniqid() },
        location: { text: "", id: uniqid() },
        duration: [
          [{ text: "", id: uniqid() }],
          [{ text: "", id: uniqid() }]
        ],
      },
    ]);
    return state;
  },
  addDesc(id, state) {
    for (let exp of state.experiences) {
      if (exp[0].title.id === id) {
        exp[0].description.push([{ text: "", id: uniqid() }]);
      }
    }
    return state;
  },
  addDiploma(state) {
    state.diplomas.push([
      { text: "", id: uniqid(), location: "", org: "", date: "" },
    ]);
    return state;
  },
  addLang(state) {
    state.languages.push([{ code: "default", id: uniqid(), level: "default", lang : "" }]);
    return state;
  },
  addSkill(state) {
    state.skills.push([{ text: "", id: uniqid() }]);
    return state;
  },
  removeElement(id, string, state) {
    if (string === "experience") {
      for (let exp of state.experiences) {
        if (Array.isArray(exp)) {
          if (exp[0].title.id === id) {
            state.experiences.splice(state.experiences.indexOf(exp), 1);
          }
        } else {
          if (exp.title.id === id) {
            state.experiences.splice(state.experiences.indexOf(exp), 1);
          }
        }
      }
    }
    if (string === "description") {
      for (let exp of state.experiences) {
        const desc = exp[0].description;
        for (let item of desc) {
          if (Array.isArray(item)) {
            if (item[0].id === id) desc.splice(item, 1);
          } else {
            if (item.id === id) desc.splice(item, 1);
          }
        }
      }
    }
    if (string === "diploma") {
      for (let diploma of state.diplomas) {
        if (diploma[0].id === id)
          state.diplomas.splice(diploma, 1);
      }
    }
    if (string === "language") {
      for (let language of state.languages) {
        if (language[0].id === id)
          state.languages.splice(language, 1);
      }
    }
    if (string === "skill") {
      for (let skill of state.skills) {
        if(skill[0].id===id){
          state.skills.splice(skill, 1);
        }
      }
    }
    return state;
  },
};

