import React from "react";
import removeIcon from "../../../svg/delete-trash-remove-svgrepo-com.svg";
import closeIcon from "../../../svg/delete-svgrepo-com.svg";
class Form extends React.Component {
  constructor(props) {
    super(props);
    this.handleChange = this.handleChange.bind(this);
    this.addDesc = this.addDesc.bind(this);
    this.removeMe = this.removeMe.bind(this);
  }
  handleChange(e) {
    this.props.onDataChange.updateExp(
      e.target.id,
      e.target.value,
      e.target.className,
      this.props.data
    );
  }
  addDesc(e) {
    this.props.onDataChange.addDesc(e.target.id);
  }
  removeMe(e) {
    this.props.onDataChange.removeElement(e.target.id, "experience");
  }
  render() {
    const arr = this.props.data.map((el) =>
      el.description.map((el) => (
        <Description data={el} onDataChange={this.props.onDataChange} />
      ))
    );
    return (
      <div className="form">
        <div className="sub-container">
          <div data-style="label-input">
            <h4>Title</h4>
            <input
              value={this.props.data[0].title.text}
              onChange={this.handleChange}
              className="title"
              id={this.props.data[0].title.id}
            ></input>
          </div>
          <Employer
            data={this.props.data[0]}
            onDataChange={this.props.onDataChange}
          />
          <Location
            data={this.props.data[0]}
            onDataChange={this.props.onDataChange}
          />
          <Duration
            data={this.props.data[0]}
            onDataChange={this.props.onDataChange}
          />
          <div className="sub-container">
            <h4>Description</h4>
            <div className="wrapper">{arr}</div>
          </div>
          <button onClick={this.addDesc} id={this.props.data[0].title.id}>
            Add Description
          </button>
        </div>
        <img
          src={removeIcon}
          onClick={this.removeMe}
          id={this.props.data[0].title.id}
          alt="remove"
        ></img>
      </div>
    );
  }
}
class Duration extends React.Component {
  constructor() {
    super();
    this.handleChange = this.handleChange.bind(this);
  }
  handleChange(e) {
    this.props.onDataChange.updateDuration(e.target.id, e.target.value);
  }
  render() {
    return (
      <div className="sub-container">
        <h4>Duration</h4>
        <div data-style="label-input">
          <label>From</label>
          <input
            value={this.props.data.duration[0][0].text}
            onChange={this.handleChange}
            id={this.props.data.duration[0][0].id}
            pattern="[0-9]{2}[//][0-9]{4}"
          ></input>
        </div>
        <div data-style="label-input">
          <label>To</label>
          <input 
          value={this.props.data.duration[1][0].text}
          onChange={this.handleChange}
          id={this.props.data.duration[1][0].id}
          pattern="([0-9]{2}[//][0-9]{4} | [Present])"
          ></input>
        </div>
      </div>
    );
  }
}
