class Description extends React.Component {
  constructor(props) {
    super(props);
    this.handleChange = this.handleChange.bind(this);
    this.removeMe = this.removeMe.bind(this);
  }
  handleChange(e) {
    this.props.onDataChange.updateExp(
      e.target.id,
      e.target.value,
      e.target.className
    );
  }
  removeMe(e) {
    this.props.onDataChange.removeElement(e.target.id, "description");
  }
  render() {
    let data = null;
    if (Array.isArray(this.props.data)) data = this.props.data[0];
    else {
      data = this.props.data;
    }
    return (
      <div data-style="input-close">
        <input
          className="description"
          value={data.text}
          id={data.id}
          onChange={this.handleChange}
        ></input>
        <img
          src={closeIcon}
          onClick={this.removeMe}
          id={data.id}
          alt="close"
        ></img>
      </div>
    );
  }
}
export default Form;
