import React from "react";
import closeIcon from "../../svg/delete-svgrepo-com.svg";
class Skills extends React.Component {
  render() {
    const skillsList = this.props.skills.map((el) => (
      <Skill data={el[0]} onDataChange={this.props.onDataChange} />
    ));
    return (
        <div className="wrapper">{skillsList}</div>
    );
  }
}
class Skill extends React.Component {
  constructor() {
    super();
    this.handleChange = this.handleChange.bind(this);
    this.removeMe = this.removeMe.bind(this);
  }
  removeMe(e) {
    this.props.onDataChange.removeElement(e.target.id, "skill");
  }
  handleChange(e) {
    this.props.onDataChange.updateSkill(e.target.id, e.target.value);
  }
  render() {
    return (
      <div data-style="input-close">
        <input
          value={this.props.data.text}
          id={this.props.data.id}
          onChange={this.handleChange}
        ></input>
        <img
          src={closeIcon}
          onClick={this.removeMe}
          id={this.props.data.id}
          alt="close"
        ></img>
      </div>
    );
  }
}
export default Skills;
