import React from "react";
import Form from "./Form";
class Experience extends React.Component {
  render() {
    const listForms = this.props.experiences.map((experience) => (
      <Form data={experience} onDataChange={this.props.onDataChange} />
    ));
    return (
      <>
        {listForms}
      </>
    );
  }
}
export default Experience;
