import React from "react";
class Skills extends React.Component{
    render(){
        const skillsList = this.props.skills.map((el) => (
            <div className="skill-item">
                {el[0].text}
            </div>
          ));
        return(
           <div className="container skills">
                {skillsList}
           </div>
        )
    }
}
export default Skills;