import React from "react";
class About extends React.Component {
  constructor(props) {
    super(props);
    this.handleChange = this.handleChange.bind(this);
  }
  handleChange = (e) => {
    if (e.target.id === "about")
      this.props.onDataChange.stringUpdate(e.target.value, "about");
    if (e.target.id === "title")
      this.props.onDataChange.stringUpdate(e.target.value, "title");
  };
  render() {
    return (
      <div className="sub-container">
        <div className="sub-container">
          <label>What is your current position or the one you're seeking</label>
          <input
            value={this.props.title}
            onChange={this.handleChange}
            id="title"
          ></input>
        </div>
        <div className="sub-container">
          <label>Tell something about yourself</label>
          <textarea
            value={this.props.about}
            onChange={this.handleChange}
            id="about"
          ></textarea>
        </div>
      </div>
    );
  }
}
export default About;
