import React from "react";
import removeIcon from "../../svg/delete-trash-remove-svgrepo-com.svg";
class Diplomas extends React.Component {
  constructor(props) {
    super(props);
    this.handleChange = this.handleChange.bind(this);
    this.removeMe = this.removeMe.bind(this);
  }
  handleChange(e) {
    this.props.onDataChange.updateDiploma(
      e.target.id,
      e.target.value,
      e.target.className
    );
  }
  removeMe(e) {
    this.props.onDataChange.removeElement(e.target.id, "diploma");
  }
  render() {
    const diplomasList = this.props.diplomas.map((el) => (
      <div className="form">
        <div className="sub-container">
          <div data-style="label-input">
            <label>Title</label>
            <input
              type="text"
              value={el[0].title}
              id={el[0].id}
              className="title"
              onChange={this.handleChange}
            ></input>
          </div>
          <div data-style="label-input">
            <label>Year</label>
            <input
              type="text"
              value={el[0].date}
              id={el[0].id}
              className="date"
              onChange={this.handleChange}
              pattern="[0-9]{4}"
              title="Please enter a year (2023)"
            ></input>
          </div>
          <div data-style="label-input">
            <label>Name of Establishment</label>
            <input
              type="text"
              value={el[0].org}
              id={el[0].id}
              className="org"
              onChange={this.handleChange}
            ></input>
          </div>
          <div data-style="label-input">
            <label>Location</label>
            <input
              type="text"
              value={el[0].location}
              id={el[0].id}
              className="location"
              onChange={this.handleChange}
            ></input>
          </div>
        </div>
        <img
          src={removeIcon}
          onClick={this.removeMe}
          id={el[0].id}
          alt="remove"
        ></img>
      </div>
    ));
    return <>{diplomasList}</>;
  }
}
export default Diplomas;
