import React from "react";
class Diplomas extends React.Component {
  render() {
    const diplomasList = this.props.diplomas.map((el) => (
      <div>
        <div className="diploma">
          <h4>{el[0].title}</h4>
          <span> - </span>
          <p>{el[0].date}</p>
        </div>
        <div className="diploma">
          <p>{el[0].org}</p>
          <span> - </span>
          <p>{el[0].location}</p>
        </div>
      </div>
    ));
    return <>{diplomasList}</>;
  }
}
export default Diplomas;
