import React from "react";
import Personal from "./Personal";
import Address from "./Address";
import About from "./About";
import Experience from "./experiences/Experiences";
import Diplomas from "./Diplomas";
import Languages from "./Languages";
import Skills from "./Skills";
class Edit extends React.Component {
  constructor(props) {
    super(props);
    this.newForm = this.newForm.bind(this);
    this.addDiploma = this.addDiploma.bind(this);
    this.addLanguage = this.addLanguage.bind(this);
    this.handleChange = this.addSkill.bind(this);
  }
  newForm() {
    this.props.onDataChange.addExp();
  }
  addDiploma() {
    this.props.onDataChange.addDiploma();
  }
  addLanguage() {
    this.props.onDataChange.addLang();
  }
  addSkill() {
    this.props.onDataChange.addSkill();
  }
  render() {
    return (
      <div className="inputs">
        <div className="container edit">
          <h4 className="title prev">Personal Details</h4>
          <Personal
            details={this.props.data.details}
            onDataChange={this.props.onDataChange}
          />
          <h4 className="title prev">Address</h4>
          <Address
            address={this.props.data.address}
            onDataChange={this.props.onDataChange}
          />
        </div>
        <div className="container edit">
          <h4 className="title prev">About Yourself</h4>
          <About
            about={this.props.data.about}
            title={this.props.data.title}
            onDataChange={this.props.onDataChange}
          />
        </div>
        <div className="container edit">
          <h4 className="title prev">Experiences</h4>
          <Experience
            experiences={this.props.data.experiences}
            onDataChange={this.props.onDataChange}
          />
          <button onClick={this.newForm}>Add Experience</button>
        </div>
        <div className="container edit">
          <h4 className="title prev">Diplomas</h4>
          <Diplomas
            diplomas={this.props.data.diplomas}
            onDataChange={this.props.onDataChange}
          />
          <button onClick={this.addDiploma}>Add Diploma</button>
        </div>
        <div className="container edit">
          <h4 className="title prev">Languages</h4>
          <Languages
            languages={this.props.data.languages}
            onDataChange={this.props.onDataChange}
          />
          <button onClick={this.addLanguage}>Add Language</button>
        </div>
        <div className="container edit">
          <h4 className="title prev">Skills</h4>
          <h5>Describe in a few words your different skills</h5>
          <Skills
            skills={this.props.data.skills}
            onDataChange={this.props.onDataChange}
          />
          <button onClick={this.handleChange}>Add Skill</button>
        </div>
      </div>
    );
  }
}
export default Edit;
