import React from "react";
class Personal extends React.Component {
  constructor(props) {
    super(props);
    this.handleChange = this.handleChange.bind(this);
  }
  handleChange = (e) => {
    this.props.onDataChange.stringUpdate(e.target.value, e.target.id);
  };
  render() {
    return (
      <div className="sub-container">
        <div data-style="label-input">
          <label>First Name</label>
          <input
            type="text"
            value={this.props.details.firstName}
            onChange={this.handleChange}
            id="first"
            pattern="[A-Za-z]+"
          ></input>
        </div>
        <div data-style="label-input">
          <label>Last Name</label>
          <input
            type="text"
            value={this.props.details.lastName}
            onChange={this.handleChange}
            id="last"
            pattern="[A-Za-z]+"
          ></input>
        </div>
        <div data-style="label-input">
          <label>Phone Number</label>
          <input
            pattern="[0-9]{10}"
            value={this.props.details.phone}
            onChange={this.handleChange}
            id="phone"
            type="tel"
          ></input>
        </div>
        <div data-style="label-input">
          <label>Email</label>
          <input
            type="email"
            value={this.props.details.email}
            onChange={this.handleChange}
            id="email"
          ></input>
        </div>
      </div>
    );
  }
}
export default Personal;
