import React from "react";
class Languages extends React.Component{
    render(){
        const languagesList = this.props.languages.map((el) =>
            <div className="title language">
                {el[0].lang}    
                <div className="level">
                    {el[0].level}
                </div>
            </div>
        )
        return(
            <div>
                {languagesList}
            </div>
        )
    }
}
export default Languages;